// Extract SKU from folder name
// Supports Pattern A: /products/{SKU}/ and Pattern B: flat {SKU}_image1.jpg

const items = $input.all();
const results = [];

for (const item of items) {
  const folderName = item.json.name;
  const folderId = item.json.id;
  const webViewLink = item.json.webViewLink;

  // Pattern A: Folder name is the SKU
  let sku = folderName.trim().toUpperCase();

  // Check if this looks like a valid SKU (alphanumeric, dashes, underscores)
  const skuPattern = /^[A-Z0-9_-]+$/;

  if (skuPattern.test(sku)) {
    results.push({
      json: {
        sku: sku,
        folder_id: folderId,
        folder_name: folderName,
        folder_link: webViewLink,
        pattern_type: 'A',
        source_tier: 1,
        vendor_id: item.json.vendor_id || $('Start').first().json.vendor_id
      }
    });
  }
}

return results;

// Categorize files into images, videos, and documents
// Generate shareable links

const items = $input.all();
const productData = {};

for (const item of items) {
  const sku = item.json.sku;
  const fileName = item.json.name;
  const mimeType = item.json.mimeType;
  const webContentLink = item.json.webContentLink;
  const webViewLink = item.json.webViewLink;

  if (!productData[sku]) {
    productData[sku] = {
      sku: sku,
      vendor_id: item.json.vendor_id,
      image_urls: [],
      video_urls: [],
      document_urls: [],
      source_tier: 1,
      last_updated: new Date().toISOString()
    };
  }

  // Categorize by MIME type
  if (mimeType.startsWith('image/')) {
    productData[sku].image_urls.push({
      url: webContentLink || webViewLink,
      filename: fileName,
      type: 'image'
    });
  } else if (mimeType.startsWith('video/')) {
    productData[sku].video_urls.push({
      url: webContentLink || webViewLink,
      filename: fileName,
      type: 'video'
    });
  } else if (mimeType.includes('document') || mimeType.includes('pdf') || mimeType.includes('text')) {
    productData[sku].document_urls.push({
      url: webViewLink,
      filename: fileName,
      type: 'document'
    });
  }
}

// Convert to array
const results = Object.values(productData).map(data => ({ json: data }));

return results;

// Handle Pattern B: Flat structure with {SKU}_filename.ext

const items = $input.all();
const results = [];

for (const item of items) {
  const fileName = item.json.name;

  // Pattern B: Extract SKU from filename (e.g., ABC123_image1.jpg)
  const patternB = /^([A-Z0-9_-]+)_/i;
  const match = fileName.match(patternB);

  if (match) {
    const sku = match[1].toUpperCase();
    const mimeType = item.json.mimeType;
    const webContentLink = item.json.webContentLink;
    const webViewLink = item.json.webViewLink;

    results.push({
      json: {
        sku: sku,
        filename: fileName,
        mime_type: mimeType,
        url: webContentLink || webViewLink,
        pattern_type: 'B',
        vendor_id: item.json.vendor_id || $('Start').first().json.vendor_id
      }
    });
  }
}

return results;

// Group Pattern B files by SKU

const items = $input.all();
const productData = {};

for (const item of items) {
  const sku = item.json.sku;
  const mimeType = item.json.mime_type;
  const url = item.json.url;
  const filename = item.json.filename;

  if (!productData[sku]) {
    productData[sku] = {
      sku: sku,
      vendor_id: item.json.vendor_id,
      image_urls: [],
      video_urls: [],
      document_urls: [],
      source_tier: 1,
      pattern_type: 'B',
      last_updated: new Date().toISOString()
    };
  }

  // Categorize by MIME type
  if (mimeType.startsWith('image/')) {
    productData[sku].image_urls.push({
      url: url,
      filename: filename,
      type: 'image'
    });
  } else if (mimeType.startsWith('video/')) {
    productData[sku].video_urls.push({
      url: url,
      filename: filename,
      type: 'video'
    });
  } else if (mimeType.includes('document') || mimeType.includes('pdf') || mimeType.includes('text')) {
    productData[sku].document_urls.push({
      url: url,
      filename: filename,
      type: 'document'
    });
  }
}

// Convert to array
const results = Object.values(productData).map(data => ({ json: data }));

return results;

// Extract marketing copy from documents
// This is a placeholder - in production, you'd read the document content

const items = $input.all();
const results = [];

for (const item of items) {
  const productData = { ...item.json };

  // If there are document URLs, note that marketing copy should be extracted
  if (productData.document_urls && productData.document_urls.length > 0) {
    productData.marketing_copy_source = productData.document_urls[0].url;
    productData.marketing_copy = 'Marketing copy available in document. Extract manually or use AI.';
  } else {
    productData.marketing_copy = '';
  }

  // Add metadata
  productData.metadata = {
    total_images: productData.image_urls.length,
    total_videos: productData.video_urls.length,
    total_documents: productData.document_urls.length,
    pattern_type: productData.pattern_type || 'A',
    source: 'google_drive'
  };

  results.push({ json: productData });
}

return results;
